      oraliq_dars_question: 442,
      answer_uz: "Piyodalar o’tish joyidan to’xtamasdan o’tish",
      answer_ru: "Проехать пешеходный переход безостановочно",
      answer_cry: "Пиёдалар ўтиш жойидан тўхтамасдан ўтиш",
      created_at: "2024-09-13T07:10:06.772Z",
