      id: 1594,
      oraliq_dars_question: 475,
      answer_uz: "Chorrahalarda trotuarlar yoki yo'l yoqasi chiziqlari bo'ylab",
      answer_ru: "На перекрестках по линии тротуаров или обочин",
      answer_cry: "Чорраҳаларда тротуарлар ёки йўл ёқаси чизиқлари бўйлаб",
      created_at: "2024-09-13T13:21:43.210Z",
