      oraliq_dars_question: 482,
      answer_uz: "Tramvay yaqinlashib kelganda",
      answer_ru: "При приближении трамвая",
      answer_cry: "Трамвай яқинлашиб келганда",
      created_at: "2024-09-13T14:01:22.813Z",
