      id: 1618,
      oraliq_dars_question: 482,
      answer_uz: "Tramvay to’la to’xtagandan so’ng",
      answer_ru: "После полной остановки трамвая",
      answer_cry: "Трамвай тўла тўхтагандан сўнг",
