      id: 2394,
      oraliq_dars_question: 736,
      answer_uz: "Faqat chorrahalarda ruxsat beriladi",
      answer_ru: "Разрешается только на перекрестках",
      answer_cry: "Фақат чорраҳаларда рухсат берилади",
      created_at: "2024-09-19T13:34:37.429Z",
