      id: 2537,
      oraliq_dars_question: 783,
      answer_uz: "Ikkala sanab o'tilgan harakat taqiqlanadi",
      answer_ru: "Запрещаются оба перечисленных действия",
      answer_cry: "Иккала санаб ўтилган ҳаракат тақиқланади",
      created_at: "2024-09-20T14:13:13.665Z",
