      oraliq_dars_question: 810,
      answer_uz: "Har qanday tormozlashda",
      answer_ru: "При любом торможении",
      answer_cry: "Ҳар қандай тормозлашда",
      created_at: "2024-09-21T05:28:52.704Z",
